    normalizeAttendanceDateKey(value) {
      const candidate = `${value || ''}`.trim();
      if (!candidate) {
        return '';
      }
      const isoMatch = candidate.match(/\d{4}-\d{2}-\d{2}/);
      if (isoMatch) {
        return isoMatch[0];
      }
      const parsedDate = new Date(candidate);
      if (!Number.isNaN(parsedDate.getTime())) {
        return this.toIsoDate(parsedDate);
      }
      const slashMatch = candidate.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
      if (slashMatch) {
        const [, day, month, year] = slashMatch;
        return `${year}-${month}-${day}`;
      }
      return '';
    }
    mapAttendanceState(item, checkIn, checkOut) {
      const rawStatus = `${item.attendance_status || item.attendanceStatus || item.day_status || item.dayStatus || item.status || ''}`.trim().toLowerCase().replace(/[_-]+/g, ' ');
      if (item.is_holiday || item.is_weekoff || rawStatus.includes('holiday') || rawStatus.includes('special day') || rawStatus.includes('festival') || rawStatus.includes('important') || rawStatus.includes('week off') || rawStatus.includes('weekoff') || rawStatus.includes('weekend')) {
        return 'holiday';
      }
      if (rawStatus.includes('half')) {
        return 'half-day';
      }
      if (rawStatus.includes('leave')) {
        return 'leave';
      }
      if (rawStatus.includes('late')) {
        return 'late';
      }
      if (rawStatus.includes('present')) {
        return 'present';
      }
      if (rawStatus.includes('absent')) {
        return 'absent';
      }
