          hour: 'numeric',
          minute: '2-digit'
        });
      }
      return candidate;
    }
    resolveWorkingHours(item, checkIn, checkOut, state) {
      const candidate = `${item.working_hours || item.workingHours || item.total_hours || item.totalHours || ''}`.trim();
      if (candidate) {
        return candidate;
      }
      const derivedHours = this.calculateWorkingHours(checkIn, checkOut);
      if (derivedHours) {
        return derivedHours;
      }
      switch (state) {
        case 'leave':
          return 'Approved Leave';
        case 'holiday':
          return 'Special Day';
        case 'weekend':
          return 'Special Day';
        case 'upcoming':
          return 'Pending';
        default:
          return '--';
      }
    }
    calculateWorkingHours(checkIn, checkOut) {
      const start = this.parseDisplayTime(checkIn);
      const end = this.parseDisplayTime(checkOut);
      if (!start || !end) {
