      }
      let diffMinutes = end.hours * 60 + end.minutes - (start.hours * 60 + start.minutes);
      if (diffMinutes < 0) {
        diffMinutes += 24 * 60;
      }
      const hours = `${Math.floor(diffMinutes / 60)}`.padStart(2, '0');
