      }
      const twelveHourMatch = candidate.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);
      if (twelveHourMatch) {
        let hours = Number(twelveHourMatch[1]) % 12;
        const minutes = Number(twelveHourMatch[2]);
        if (twelveHourMatch[3].toUpperCase() === 'PM') {
          hours += 12;
        }
        return {
